import React, { useCallback, useEffect, useState } from "react";
import "../styles/RecipeRatingInput.css";

function RecipeRatingInput({ recipe, onRatingSaved }) {
  let [userRating, setUserRating] = useState(0);
  let [hoveredRating, setHoveredRating] = useState(0);
  let [loading, setLoading] = useState(false);

  let loggedUser = localStorage.getItem("loggedUser");
  let user = loggedUser ? JSON.parse(loggedUser) : null;

  let loadUserRating = useCallback(async () => {
    if (!user || !recipe?.api_przepis_id) {
      setUserRating(0);
      return;
    }

    try {
      let response = await fetch(
        `http://localhost:5000/api/oceny/uzytkownika?uzytkownik_id=${user.id}&api_przepis_id=${recipe.api_przepis_id}`
      );
      let data = await response.json();
      setUserRating(data.ocena || 0);
    } catch (error) {
      console.log(error);
    }
  }, [recipe?.api_przepis_id, user]);

  useEffect(() => {
    loadUserRating();
  }, [loadUserRating]);

  async function handleRate(value) {
    if (!user || !recipe?.api_przepis_id) return;

    try {
      setLoading(true);

      let response = await fetch("http://localhost:5000/api/oceny", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          uzytkownik_id: user.id,
          recipe: recipe,
          ocena: value
        })
      });

      let data = await response.json();

      if (!response.ok) {
        console.log(data.error);
        setLoading(false);
        return;
      }

      setUserRating(value);
      setLoading(false);

      if (onRatingSaved) {
        onRatingSaved({
          srednia_ocen: data.srednia_ocen,
          liczba_opinii: data.liczba_opinii
        });
      }

      window.dispatchEvent(new Event("ratingsChanged"));
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  }

  if (!user) return null;

  return (
    <div className="rating-input-box">
      <p className="rating-input-label">
        Twoja ocena:
        {userRating > 0 ? ` ${userRating}/5` : " wybierz gwiazdkę"}
      </p>

      <div className="rating-input-stars">
        {[1, 2, 3, 4, 5].map((value) => {
          let active = value <= (hoveredRating || userRating);

          return (
            <button
              key={value}
              type="button"
              className={active ? "rating-star-btn active" : "rating-star-btn"}
              onMouseEnter={() => setHoveredRating(value)}
              onMouseLeave={() => setHoveredRating(0)}
              onClick={() => handleRate(value)}
              disabled={loading}
            >
              ★
            </button>
          );
        })}
      </div>
    </div>
  );
}

export default RecipeRatingInput;
